function Cart({ cart }) {
    return (
      <div style={styles.cart}>
        <h2>Cart</h2>

        {cart.length === 0 ? (
          <p>No items in cart</p>
        ) : (
          cart.map((item, index) => (
            <div key={index}>
              {item.name} - ${item.price}
            </div>
          ))
        )}
      </div>
    );
  }

  const styles = {
    cart: {
      marginTop: "20px",
      padding: "10px",
      borderTop: "2px solid black"
    }
  };

  export default Cart;
